module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
    // TODO: Implement div_16bit
    // Note: Do not change the port name and width
    reg [15:0] SR;
    reg [3:0] cnt;
    reg [15:0] NEG_DIVISOR;
    reg start_cnt;
    reg [15:0] DIVIDEND;
    reg [15:0] DIVISOR;
    always @(posedge clk or negedge rst) begin
        if(!rst)begin
            DIVIDEND <= 16'b0;
            DIVISOR <= 16'b0;
        end else if(opn_valid && !res_valid)begin
            DIVIDEND <= dividend;
            DIVISOR <= divisor;
        end
    end
    always @(posedge clk or negedge rst) begin
        if(!rst)begin
            SR <= 16'b0;
            NEG_DIVISOR <= 16'b0;
            cnt <= 4'b0;
            start_cnt <= 1'b0;
        end else if(opn_valid && !res_valid)begin
            SR <= {DIVIDEND[15], DIVIDEND, 1'b0};
            NEG_DIVISOR <= (~DIVISOR) + 1;
            cnt <= 4'b1;
            start_cnt <= 1'b1;
        end else if(start_cnt)begin
            if(cnt[3] == 1'b1)begin
                cnt <= 4'b0;
                start_cnt <= 1'b0;
                SR <= {NEG_DIVISOR, 1'b0, SR[14:1]};
            end else begin
                cnt <= cnt + 1;
                start_cnt <= 1'b1;
                if(SR[15] == 1'b0)begin
                    SR <= {SR[15:0], 1'b0};
                end else begin
                    SR <= {SR[15:0] + NEG_DIVISOR, 1'b1};
                end
            end
        end
    end
    always @(posedge clk or negedge rst) begin
        if(!rst)begin
            res_valid <= 1'b0;
        end else if(cnt == 4'b1000)begin
            res_valid <= 1'b1;
        end else if(res_valid && res_ready)begin
            res_valid <= 1'b0;
        end
    end
    always @(posedge clk or negedge rst) begin
        if(!rst)begin
            result <= 16'b0;
        end else if(cnt == 4'b1000)begin
            result <= {SR[15:0], SR[15:8]};
        end
    end
endmodule
